import{_ as a,o as i,c as s,ag as o}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Transitorios y sobretensiones","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/transients-surges.md","filePath":"es/power-quality/transients-surges.md"}'),n={name:"es/power-quality/transients-surges.md"};function r(t,e,l,c,d,p){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="transitorios-y-sobretensiones" tabindex="-1">Transitorios y sobretensiones <a class="header-anchor" href="#transitorios-y-sobretensiones" aria-label="Permalink to &quot;Transitorios y sobretensiones&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los transitorios y sobretensiones son eventos de sobrevoltaje de corta duración que ocurren en sistemas eléctricos.</p><p>Se caracterizan por cambios muy rápidos en el voltaje que pueden alcanzar amplitudes elevadas en un tiempo muy breve.</p><p>Estos eventos pueden dañar el equipo, degradar el aislamiento y afectar la confiabilidad del sistema.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Comprender los transitorios y sobretensiones es importante para:</p><ul><li>Proteger el equipo de picos de alto voltaje</li><li>Prevenir fallas prematuras del aislamiento y los componentes</li><li>Mantener la operación confiable de dispositivos sensibles</li><li>Reducir el tiempo de inactividad causado por perturbaciones eléctricas</li></ul><p>El control adecuado de estos eventos mejora la durabilidad y estabilidad del sistema.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Los transitorios y sobretensiones son causados por cambios súbitos en las condiciones eléctricas.</p><p>Las causas comunes incluyen:</p><ul><li>Operaciones de conmutación, como encender o apagar cargas</li><li>Energización o desenergización de transformadores y capacitores</li><li>Descargas atmosféricas o perturbaciones externas</li><li>Eliminación de fallas y operación de dispositivos de protección</li></ul><p>Estos eventos generan picos de voltaje de alta frecuencia que se propagan a través del sistema.</p><p>Su impacto depende de:</p><ul><li>Magnitud del voltaje pico</li><li>Tiempo de subida y duración</li><li>Impedancia del sistema y puesta a tierra</li><li>Ubicación respecto al equipo sensible</li></ul><p>Incluso eventos muy breves pueden causar daños debido a la alta concentración de energía.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los transitorios y sobretensiones son relevantes en:</p><ul><li>Instalaciones industriales con operaciones de conmutación frecuentes</li><li>Sistemas con equipos electrónicos sensibles</li><li>Instalaciones exteriores expuestas a descargas atmosféricas</li><li>Tableros de control y sistemas de automatización</li><li>Redes de distribución de potencia</li></ul><p>Deben considerarse tanto en las etapas de diseño como de operación.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Magnitud de voltaje</strong><br> Picos más altos incrementan el riesgo de ruptura del aislamiento</p></li><li><p><strong>Frecuencia y repetición</strong><br> Eventos repetidos pueden causar daños acumulativos</p></li><li><p><strong>Fuente de la perturbación</strong><br> Las fuentes internas y externas requieren enfoques de mitigación diferentes</p></li><li><p><strong>Puesta a tierra del sistema</strong><br> Una puesta a tierra adecuada ayuda a controlar el comportamiento transitorio</p></li><li><p><strong>Dispositivos de protección</strong><br> Los dispositivos de protección contra sobretensiones pueden limitar los picos de voltaje</p></li><li><p><strong>Sensibilidad del equipo</strong><br> Los sistemas electrónicos son más vulnerables que las cargas resistivas</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Las operaciones de conmutación son una fuente interna común de transitorios</li><li>La protección contra descargas atmosféricas es crítica en instalaciones expuestas</li><li>Los dispositivos de protección contra sobretensiones deben instalarse cerca del equipo sensible</li><li>Una puesta a tierra deficiente incrementa el impacto de los eventos transitorios</li><li>La inspección regular garantiza que los dispositivos de protección sigan siendo efectivos</li></ul>',25)])])}const b=a(n,[["render",r]]);export{m as __pageData,b as default};
